#include <bits/stdc++.h>
using namespace std;
int main() {
    // ── Constructors ──
    vector<int> a;                    // empty vector
    vector<int> b(5);                 // 5 elements, all 0
    vector<int> c(5, -1);            // 5 elements, all -1
    vector<int> d = {3, 1, 4, 1, 5}; // initializer list
    vector<int> e(d);                 // copy of d
    vector<int> f(d.begin() + 1, d.end() - 1); // slice: {1, 4, 1}

    // ── Size & Capacity ──
    cout << d.size()     << "\n";  // number of elements: 5
    cout << d.empty()    << "\n";  // 0 (not empty)
    cout << d.capacity() << "\n";  // internal buffer size (≥ size)

    // ── Reading into vector ──
    int n = 5;
    vector<int> v(n);
    for (int i = 0; i < n; i++) cin >> v[i];
    // Or:
    vector<int> v2;
    v2.reserve(n);                   // pre-allocate, avoid reallocations
    for (int i = 0; i < n; i++) {
        int x; cin >> x;
        v2.push_back(x);
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {10, 20, 30};

    // ── Adding elements ──
    v.push_back(40);          // append: O(1) amortized  → {10,20,30,40}
    v.emplace_back(50);       // construct-in-place (faster for objects) → {10,20,30,40,50}
    v.insert(v.begin(), 0);   // insert at front: O(n)  → {0,10,20,30,40,50}
    v.insert(v.begin() + 2, 99); // insert at index 2: O(n)

    // ── Removing elements ──
    v.pop_back();              // remove last: O(1)      → no 50
    v.erase(v.begin());        // remove first: O(n)
    v.erase(v.begin()+1, v.begin()+3); // remove range [1, 3): O(n)
    v.clear();                 // remove all: O(n)

    // ── Access ──
    vector<int> w = {5, 6, 7, 8, 9};
    cout << w[2]       << "\n";   // 7 — no bounds check
    cout << w.at(2)    << "\n";   // 7 — throws if out of range
    cout << w.front()  << "\n";   // 5 — first element
    cout << w.back()   << "\n";   // 9 — last element

    // ── Swap (O(1) — just swaps internal pointers) ──
    vector<int> x = {1,2}, y = {3,4,5};
    swap(x, y);  // x is now {3,4,5}, y is {1,2}

    // ── Resize ──
    w.resize(8);     // extends to 8 elements, new ones are 0
    w.resize(3);     // truncates to first 3 elements
    w.assign(5, 7);  // replace all contents with five 7s

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {10, 20, 30, 40, 50};

    // ── Index-based (most common in CP) ──
    for (int i = 0; i < (int)v.size(); i++)
        cout << v[i] << " ";
    cout << "\n";

    // ── Range-based (clean, read-only) ──
    for (int x : v) cout << x << " ";
    cout << "\n";

    // ── Range-based with reference (modify elements) ──
    for (int& x : v) x *= 2;
    // v is now {20,40,60,80,100}

    // ── Reverse iteration ──
    for (int i = (int)v.size() - 1; i >= 0; i--)
        cout << v[i] << " ";
    cout << "\n";
    // Or using reverse iterators:
    for (auto it = v.rbegin(); it != v.rend(); ++it)
        cout << *it << " ";
    cout << "\n";

    // ── DANGER: compare size() with int ──
    // for (int i = 0; i < v.size() - 1; i++) // BUG if v is empty!
    // v.size() returns size_t (unsigned). If v is empty, v.size()-1 wraps
    // to a huge positive number → infinite loop or crash.
    // Fix: cast to int: (int)v.size() - 1
    return 0;
}

