#include <bits/stdc++.h>
using namespace std;
int main() {
    // ── Declaration ──
    pair<int, int> p1 = {3, 7};
    pair<int, string> p2 = make_pair(1, "hello");  // older style
    auto p3 = make_pair(3.14, 'A');                 // type deduction

    // ── Access ──
    cout << p1.first << " " << p1.second << "\n";   // 3 7

    // ── Comparison (lexicographic!) ──
    pair<int,int> a = {1, 5}, b = {1, 3}, c = {2, 0};
    cout << (a > b) << "\n";   // 1 (true: same first, 5 > 3)
    cout << (a < c) << "\n";   // 1 (true: 1 < 2 in first field)

    // ── Sort vector of pairs: by first, then second ──
    vector<pair<int,int>> v = {{3,1},{1,4},{1,2},{2,7}};
    sort(v.begin(), v.end());
    // Result: {{1,2},{1,4},{2,7},{3,1}}

    // ── Sort by second value ──
    sort(v.begin(), v.end(), [](auto& a, auto& b){
        return a.second < b.second;
    });

    // ── Sort by first descending, second ascending ──
    sort(v.begin(), v.end(), [](auto& a, auto& b){
        if (a.first != b.first) return a.first > b.first;  // desc first
        return a.second < b.second;                         // asc second
    });

    // ── Structured bindings (C++17) — cleaner access ──
    for (auto& [x, y] : v)
        cout << x << "," << y << " ";
    cout << "\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    // ── Construction ──
    tuple<int, int, int> t1 = {1, 2, 3};
    auto t2 = make_tuple("edge", 5, 3.14);

    // ── Access via get<index> ──
    cout << get<0>(t1) << " " << get<1>(t1) << " " << get<2>(t1) << "\n";

    // ── Structured bindings (C++17) — by far the cleanest ──
    auto [w, u, v] = t1;
    cout << w << " " << u << " " << v << "\n";

    // ── Sorting tuples (lexicographic by default) ──
    // Classic use: Kruskal's MST — sort edges by weight
    vector<tuple<int,int,int>> edges;  // {weight, from, to}
    edges.emplace_back(4, 1, 2);
    edges.emplace_back(1, 2, 3);
    edges.emplace_back(3, 1, 3);
    sort(edges.begin(), edges.end());  // sorts by weight (first element)
    // After sort: {1,2,3}, {3,1,3}, {4,1,2}

    // ── tie — unpack into existing variables ──
    int x, y, z;
    tie(x, y, z) = t1;  // x=1, y=2, z=3

    return 0;
}

// Map arbitrary large values to small indices [0, k-1]
// Use case: values up to 10^9 but only n ≤ 10^5 distinct values
vector<int> arr = {1000000000, 42, 7, 42, 1000000000};
vector<int> comp = arr;                     // copy
sort(comp.begin(), comp.end());             // sort
comp.erase(unique(comp.begin(), comp.end()), comp.end()); // deduplicate
// Now comp = {7, 42, 1000000000} — sorted unique values

// Convert original values to compressed indices:
for (int& x : arr) {
    x = lower_bound(comp.begin(), comp.end(), x) - comp.begin();
}
// arr is now: {2, 1, 0, 1, 2}

// Sort n items by some computed key without a comparator:
// Instead of a lambda, store (key, original_index) as pairs
vector<int> a = {5, 2, 8, 1, 9};
vector<pair<int,int>> keyed;
for (int i = 0; i < (int)a.size(); i++)
    keyed.emplace_back(a[i], i);            // {value, original_index}
sort(keyed.begin(), keyed.end());           // sorts by value, ties by index

for (auto& [val, idx] : keyed)
    cout << "a[" << idx << "] = " << val << "\n";
// Output: a[3]=1, a[1]=2, a[0]=5, a[2]=8, a[4]=9

