#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<pair<int,string>> players(n);
    for (auto& [score, name] : players)
        cin >> score >> name;
    // Negation trick: sort by -score asc, then name asc
    sort(players.begin(), players.end(), [](auto& a, auto& b){
        if (a.first != b.first) return a.first > b.first;
        return a.second < b.second;
    });
    for (auto& [score, name] : players)
        cout << score << " " << name << "\n";
    return 0;
}

