#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<int> a(n);
    for (int& x : a) cin >> x;
    unordered_set<int> seen;
    vector<int> result;
    result.reserve(n);
    for (int x : a) {
        if (seen.insert(x).second)  // .second is true if inserted (not duplicate)
            result.push_back(x);
    }
    for (int i = 0; i < (int)result.size(); i++) {
        if (i) cout << " ";
        cout << result[i];
    }
    cout << "\n";
    return 0;
}
